const useMenuItems = () => {
  const location = useLocation();

  const [menuItems, setMenuItems] = React.useState(DEFAULT_MENU_ITEMS);

  const currentMenuItems = menuItems.map<AsideHeaderItem>((item, index) => {
    if ('type' in item || index > 5) {
